import React, { useState } from 'react';
import axios from 'axios';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function Sidebar({ loggedIn, username, setLoggedIn, setUsername, onClearHistory, onFetchMistakes, onFetchReport, onDownloadWorksheet }) {
    const [loginUser, setLoginUser] = useState('');
    const [loginPass, setLoginPass] = useState('');
    const [regUser, setRegUser] = useState('');
    const [regPass, setRegPass] = useState('');
    const [msg, setMsg] = useState('');

    const handleLogin = async () => {
        try {
            const res = await API.post('/api/login', { username: loginUser, password: loginPass });
            setMsg(res.data.message);
            if (res.data.success) {
                setLoggedIn(true);
                setUsername(loginUser);
            }
        } catch (err) {
            setMsg('网络错误');
        }
    };

    const handleRegister = async () => {
        try {
            const res = await API.post('/api/register', { username: regUser, password: regPass });
            setMsg(res.data.message);
            if (res.data.success) {
                setLoggedIn(true);
                setUsername(regUser);
            }
        } catch (err) {
            setMsg('网络错误');
        }
    };

    const handleLogout = () => {
        setLoggedIn(false);
        setUsername('游客');
        setMsg('');
    };

    return (
        <div className="w-72 bg-white/80 backdrop-blur-sm shadow-xl p-5 flex flex-col gap-4 overflow-y-auto">
            <h2 className="text-2xl font-bold text-purple-600">🧰 神奇工具箱</h2>
            <button onClick={onFetchMistakes} className="tool-btn">📖 错题本</button>
            <button onClick={onFetchReport} className="tool-btn">📊 学习周报</button>
            <button onClick={() => { }} className="tool-btn">📝 批改作业（发送内容）</button>
            <button onClick={onClearHistory} className="tool-btn">🗑️ 清空对话</button>
            <div className="flex gap-2">
                <button onClick={() => onDownloadWorksheet(false)} className="tool-btn flex-1">📥 无答案</button>
                <button onClick={() => onDownloadWorksheet(true)} className="tool-btn flex-1">📥 含答案</button>
            </div>
            <hr className="border-pink-200" />
            {loggedIn ? (
                <div>
                    <p className="text-sm font-medium">👤 {username}</p>
                    <button onClick={handleLogout} className="tool-btn mt-2">🚪 退出登录</button>
                </div>
            ) : (
                <div className="space-y-4">
                    <h3 className="font-semibold text-purple-500">🔐 登录</h3>
                    <input type="text" placeholder="用户名" value={loginUser} onChange={e => setLoginUser(e.target.value)} className="input-field" />
                    <input type="password" placeholder="密码" value={loginPass} onChange={e => setLoginPass(e.target.value)} className="input-field" />
                    <button onClick={handleLogin} className="tool-btn">登录</button>
                    <h3 className="font-semibold text-purple-500">📝 注册</h3>
                    <input type="text" placeholder="用户名" value={regUser} onChange={e => setRegUser(e.target.value)} className="input-field" />
                    <input type="password" placeholder="密码" value={regPass} onChange={e => setRegPass(e.target.value)} className="input-field" />
                    <button onClick={handleRegister} className="tool-btn">注册</button>
                    {msg && <p className="text-xs text-gray-600">{msg}</p>}
                </div>
            )}
        </div>
    );
}

export default Sidebar;
